INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00347', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '在法院審理案件中，有關證據調查之程序，下列敘述何者正確？', '["法院對於得為證據之被告自白，原則上應於有關犯罪事實之其他證據調查完畢後，始得調查", "被告陳述其自白係出於不正之方法者，除有特別規定外，非於有關犯罪事實之其他證據調查完 畢後，不得調查", "法院依職權調查證據前，應予告訴人陳述意見之機會", "法院因共同被告之利害相反，而有保護被告權利之必要時，得依職權或聲請，以裁定將共同被 告之調查證據程序分離或合併"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00348', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲、乙、丙三人共同傷害丁，次日又共同侵入戊之住宅竊盜，丁、戊均向司法警察官表示只對甲 提起告訴，事後經查明丙為戊之弟弟。下列敘述何者正確？', '["丁對甲之傷害告訴，其效力不及於乙之傷害", "戊對甲之侵入住宅竊盜告訴，其效力及於丙之侵入住宅竊盜", "丁對甲之傷害告訴，其效力及於甲之侵入住宅竊盜", "若戊要對丙之侵入住宅竊盜告訴，除表示希望追訴之外，尚必須表明要對丙告訴，否則不生告 訴之效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00349', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關搜索扣押，下列敘述何者正確？', '["依刑事訴訟法所為之扣押，具有禁止處分之效力，不得為民事假扣押、假處分之查封、扣押", "司法警察官於偵查中有相當理由認為情況急迫，有立即扣押之必要時，得逕行扣押", "司法警察官認為有扣押之必要時，得逕向該管法院聲請核發扣押裁定", "有人住居之住宅，不得於夜間入內搜索或扣押，但經檢察官或法官許可者，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00350', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '刑事程序中有關證據保全之規定，下列敘述何者錯誤？', '["告訴人於偵查中得聲請檢察官為證據保全處分，檢察官對於告訴人所為證據保全處分之聲請， 予以駁回或未於五日內為保全處分時，聲請人得逕向該管法院聲請保全證據", "告訴人聲請保全證據，於案件尚未移送檢察官時，應向調查之司法警察官或司法警察所屬機關 所在地之地方檢察署檢察官聲請", "案件於第一審法院審判中，告訴人認為證據有保全之必要者，得在第一次審判期日前，聲請法 院為保全證據處分", "告訴人於偵查中，對於其聲請保全之證據，得於實施保全證據時在場。保全證據之日、時及處 所，並應通知得在場之人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00351', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關傳聞證據法則，下列敘述何者正確？', '["警察所製作之刑案移送書，係公務員職務上所製作之紀錄文書，除顯有不可信之情況外，原則 上有證據能力", "在法院審理乙傷害丙的案件中，證人在法庭上說：「甲告訴我說他親眼看到乙用球棒攻擊丙」， 證人在法庭上的供述不是傳聞證據，原則上具有證據能力", "傳聞證據排除法則於簡式審判程序中適用之", "在法院審理甲誹謗乙的案件中，證人在法庭上說：「甲告訴我說他親眼看到乙偷了丙的錢包」， 證人在法庭上的供述不是傳聞證據，原則上有證據能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00352', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲為乙之配偶，目睹乙、丙共同竊盜及丙於竊盜後又另行性侵被害人，經檢察官就乙、丙之犯行 一併起訴，在法院審理中，甲被以證人傳喚到庭，下列敘述何者正確？', '["甲就乙、丙共同竊盜及丙性侵部分為證人時，均得拒絕證言", "甲就乙與丙共同竊盜部分為證人時，得拒絕證言，但就丙性侵被害人部分為證人時，不得拒絕 證言", "甲就主詰問所陳述有關乙竊盜之事項，於反詰問時得拒絕證言", "甲就乙、丙共同竊盜及丙性侵部分為證人時，均不得拒絕證言"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00353', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依警察偵查犯罪手冊之規定，有關詢問筆錄之製作，下列敘述何者錯誤？', '["於詢問犯罪嫌疑人時，辯護人請求調查證據、陳述意見時，應將相關情形註記於該案犯罪嫌疑 人之詢問筆錄，並請辯護人於筆錄內簽名", "辯護人有無於司法警察官或司法警察詢問犯罪嫌疑人時在場，無需記載於詢問筆錄", "受詢問人及在場之辯護人請求就筆錄之記載增刪、變更時，應將其陳述附記於筆錄。但附記辯 護人之陳述，應使受詢問人明瞭後為之", "受詢問人拒絕回答或拒絕在筆錄上簽名、蓋章或按指印時，不得強制為之，但應將其拒絕原因 或理由記載於筆錄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00354', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關性侵害案件證物之處理，下列敘述何者正確？', '["證物袋送鑑定時，不得附送相關案情資料給鑑定單位", "證物袋及相關證物鑑定後，屬告訴乃論案件，尚未提出告訴或自訴時，應由犯罪發生地之警察 機關妥善保管", "為符合性侵害案件保密原則，案由一律以被害人姓名代碼代替之", "性侵害案件之被害人採證後無法聯繫，其證物袋及相關證物送鑑定後，證物袋及相關證物自採 樣蒐集之日起，保存六個月後，仍無法聯繫被害人，證物得進行銷毀"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00355', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關犯罪剖繪之應用，下列敘述何者正確？', '["最適合應用於偶發犯", "適合應用於同類型反覆出現之案件", "適合應用於每一種犯罪類型", "心理變態的犯罪者不適合應用犯罪剖繪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00356', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警察為防止危害或犯罪，認對公共安全、公共秩序或個人生命、身體、自由、名譽或財產，將有 危害行為，或有觸犯刑事法律之虞者，得遴選第三人秘密蒐集其相關資料。有關遴選第三人秘密 蒐集資料，下列敘述何者正確？', '["凡經遴選諮詢工作請求合作之對象，必要時，得給予證明身分之文件，但不得使其直接參與辦 案行動", "遴選第三人秘密蒐集資料，應以蒐集對象為限，不得涉及其接觸及隨行之人", "遴選第三人之身分應予保密，並以代號或化名為之，其簽名並應以代號或化名代之", "經遴選之第三人，應施以蒐集資料方法及技巧之訓練，訓練由專責人員個別指導"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
